import { createStory } from './create_story.mjs';

async function main() {
  const result = await createStory({
    title: '1V1 客户端测试需求单 - 请忽略',
    template: 'client',
    priority: 'P2',
    module: '1V1',
    version: '【1V1】正式版本V2.0',
    handler: '周以天',
    description: '这是一个由自动化工具提交的测试需求单，用于验证提单流程，请忽略处理。',
  });
  console.log('RESULT:', JSON.stringify(result));
}

main().catch(err => {
  console.error('ERROR:', err.message);
  process.exit(1);
});
